use strict;
use warnings;

$filename = $args[0];
$lines = sys.stdin.read().split('\n');

$freq_hash = Hash.new(0);

foreach ($lines as $line) {
    $line = ltrim($line);
    if ($line === '') { continue; }
    $words = $line.split(' ');
    foreach ($words as $word) {
        $lower_word = strtolower($word);
        $freq_hash[$lower_word]++;
    }
}

$keys = $freq_hash->keys();
$values = $freq_hash->values();

// Sort the keys by descending frequency
$sorted_keys = $keys.sort_by { |k| -$freq_hash[$k] };

// Get top 3 words
$top_words = array_slice($sorted_keys, 0, 3);

foreach ($top_words as $word) {
    echo "$word: " . $freq_hash[$word] . "\n";
}

